const item = $input.first().json;
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const hasName  = item.contact_name  && item.contact_name.trim() !== '';
const hasEmail = item.contact_email && emailRegex.test(item.contact_email.trim());

return [{
  json: {
    ...item,
    contact_name:  item.contact_name?.trim()  || '',
    contact_email: item.contact_email?.trim() || '',
    company_name:  item.company_name?.trim()  || '',
    siret:         item.siret?.replace(/\s/g, '') || '',
    products:      Array.isArray(item.products) ? item.products : [item.products].filter(Boolean),
    quantity:      parseInt(item.quantity) || null,
    isValid:       hasName && hasEmail,
    errorMessage:  !hasName  ? 'contact_name requis' :
                   !hasEmail ? 'contact_email invalide' : null
  }
}];

const formData  = $('Valider les données').first().json;
const siretResp = $input.first().json;

let siretData = {};
try {
  const et = siretResp?.etablissement;
  if (et) {
    siretData = {
      siret_raison_sociale: et.uniteLegale?.denominationUniteLegale || '',
      siret_adresse:        [et.adresseEtablissement?.numeroVoieEtablissement,
                             et.adresseEtablissement?.typeVoieEtablissement,
                             et.adresseEtablissement?.libelleVoieEtablissement].filter(Boolean).join(' '),
      siret_code_ape:       et.uniteLegale?.activitePrincipaleUniteLegale || '',
      siret_forme_juridique: et.uniteLegale?.categorieJuridiqueUniteLegale || '',
    };
  }
} catch(e) { /* SIRET invalide ou absent — on continue */ }

return [{ json: { ...formData, ...siretData } }];

